from typing import List
class Solution:
    def validArrangement(self, pairs: List[List[int]]) -> List[List[int]]:
        graph = {}
        for u, v in pairs:
            if u not in graph:
                graph[u] = []
            if v not in graph:
                graph[v] = []
            graph[u].append(v)
            graph[v].append(u)
        start = next(k for k, v in graph.items() if len(v) == 1)
        res = [[start, start]]
        stack = [start]
        while stack:
            u = stack.pop()
            for v in graph[u]:
                if v in graph and graph[v]:
                    res.append([u, v])
                    stack.append(v)
                    graph[v].remove(u)
                    graph[u].remove(v)
        return res[::-1]
